code.C++:
class Solution {
public:
    void moveZeroes(vector<int>& nums) {
        int Index = 0;
        for (int i = 0; i < nums.size(); i++) {
            if (nums[i] != 0)
                nums[Index++] = nums[i];
        }
        while (Index < nums.size())
            nums[Index++] = 0;
    }
};

