code.C:
void moveZeroes(int nums[], int n) {
    int index = 0;
    for (int i = 0; i < n; i++) {
        if (nums[i] != 0) {
            nums[index++] = nums[i];
        }
    }
    while (index < n) {
        nums[index++] = 0;
    }
}

